  3→  BarSeriesOption,
  4→  ComposeOption,
  5→  EffectScatterSeriesOption,
  6→  GraphSeriesOption,
  7→  GridComponentOption,
  8→  HeatmapSeriesOption,
  9→  LineSeriesOption,
 10→  PieSeriesOption,
