 3→export interface ButtonProps {
 4→  /** Is this the principal call to action on the page? */
 5→  primary?: boolean;
 6→  /** What background color to use */
 7→  backgroundColor?: string;
 8→  /** How large should the button be? */
 9→  size?: 'small' | 'medium' | 'large';
10→  /** Button contents */
11→  label: string;
12→  /** Optional click handler */
13→  onClick?: (() => void) | undefined;
14→}
15→
16→/** Primary UI component for user interaction */
17→export const Button = ({
18→  primary = false,
19→  size = 'medium',
20→  backgroundColor,
21→  label,
22→  ...props
23→}: ButtonProps) => {
24→  const mode = primary ? 'storybook-button--primary' : 'storybook-button--secondary';
25→  return (
26→    <button
27→      type="button"
28→      className={['storybook-button', `storybook-button--${size}`, mode].join(' ')}
29→      style={{ backgroundColor }}
30→      {...props}
31→    >
32→      {label}
33→    </button>
34→  );
35→};
