512→								<span title="${s.status}" style="width: 8px; height: 8px; border-radius: 50%; background-color: ${s.status === 'connected' ? '#10b981' : s.status === 'unknown' ? '#6b7280' : '#ef4444'}; margin-right: 0.5rem;"></span>
513→								${s.name}
514→							</div>`,
515→					)
516→					.join('') +
517→				'</div>';
518→			metadataCards.push({
519→				title: 'MCP Servers',
